522     const ConstantRange &CR1, const ConstantRange &CR2,
523     ConstantRange::PreferredRangeType Type) {
524   if (Type == ConstantRange::Unsigned) {
525     if (!CR1.isWrappedSet() && CR2.isWrappedSet())
