554     if (Lower.ult(CR.Lower)) {
555       // L---U       : this
556       //       L---U : CR
557       if (Upper.ule(CR.Lower))
558         return getEmpty();
559 
560       // L---U       : this
561       //   L---U     : CR
562       if (Upper.ult(CR.Upper))
