610 
611     // --U  L------ : this
612     //        L--U  : CR
613     return CR;
614   }
615 
616   if (CR.Upper.ult(Upper)) {
617     // ------U L-- : this
618     // --U L------ : CR
619     if (CR.Lower.ult(Upper))
